def retry_divide(a, attempts):
    for i, b in enumerate(attempts, 1):
        try:
            result = a / b
            print(f'시도 {i}: 성공 - {result}')
            return result
        except ZeroDivisionError:
            print(f'시도 {i}: 실패')
    return None

result = retry_divide(100, [0, 0, 5])
print(f'최종 결과: {result}')

