problems.solution_code:
class AgeError(Exception):
    pass

class ScoreError(Exception):
    pass

def validate_student(name, age, score):
    if age < 0 or age > 150:
        raise AgeError(f'나이 오류: {age}는 유효하지 않습니다')
    if score < 0 or score > 100:
        raise ScoreError(f'점수 오류: {score}는 0~100 범위여야 합니다')
    print(f'{name}의 정보가 저장되었습니다')

try:
    validate_student('김파이', 25, 90)
except (AgeError, ScoreError) as e:
    print(f'오류: {e}')

try:
    validate_student('이파이', 200, 90)
except (AgeError, ScoreError) as e:
    print(f'오류: {e}')
